USE ROLE dba;

-- 13/03/2025

-- Adding new experience views

CREATE VIEW HAVEN_BASE.DIG_ARRIVALS.ANPR
( ID, LICENSE_PLATE, MAC_ADDRESS, CHANNEL_ID, DATE_TIME, EVENT_TYPE, COUNTRY, LANE, DIRECTION, CONFIDENCE_LEVEL, CREATED_AT, UPDATED_AT, HVR_IS_DELETED, HVR_CHANGE_TIME )
AS SELECT ID, LICENSE_PLATE, MAC_ADDRESS, CHANNEL_ID, DATE_TIME, EVENT_TYPE, COUNTRY, LANE, DIRECTION, CONFIDENCE_LEVEL, CREATED_AT, UPDATED_AT, HVR_IS_DELETED, HVR_CHANGE_TIME
FROM HAVEN_RAW.DIG_ARRIVALS.ANPR;

CREATE VIEW HAVEN_BASE.DIG_ARRIVALS.ANPR_DEVICE
( ID, PARK_CODE, MAC_ADDRESS, CREATED_AT, UPDATED_AT, HVR_IS_DELETED, HVR_CHANGE_TIME )
AS SELECT ID, PARK_CODE, MAC_ADDRESS, CREATED_AT, UPDATED_AT, HVR_IS_DELETED, HVR_CHANGE_TIME
FROM HAVEN_RAW.DIG_ARRIVALS."ANPR-DEVICE";

SELECT * FROM HAVEN_BASE.DIG_ARRIVALS.ANPR LIMIT 10;

