USE ROLE dba;

CREATE OR REPLACE VIEW HAVEN_BASE_ETLEAP.DIG_ARRIVALS.ANPR 
( ID, LICENSE_PLATE, MAC_ADDRESS, CHANNEL_ID, DATE_TIME, EVENT_TYPE, COUNTRY, LANE, DIRECTION, CONFIDENCE_LEVEL, CREATED_AT, UPDATED_AT, FILE_MODIFICATION_TIME, DELETED_DATE, IS_DELETED) 
AS SELECT "ID", "LICENSE_PLATE", "MAC_ADDRESS", "CHANNEL_ID", "DATE_TIME", "EVENT_TYPE", "COUNTRY", "LANE", "DIRECTION", "CONFIDENCE_LEVEL", "CREATED_AT", "UPDATED_AT", "FILE_MODIFICATION_TIME", "END_DATE", DECODE(END_DATE, NULL, FALSE, TRUE) 
FROM "HAVEN_RAW"."DIG_ARRIVALS_ETLEAP"."ANPR";

