FROM "HAVEN_RAW"."DIG_ARRIVALS_ETLEAP"."ANPR_DEVICE";

CREATE OR REPLACE VIEW HAVEN_BASE_ETLEAP.DIG_ARRIVALS.ARRIVAL 
( ID, PARK_CODE, ARRIVAL_DATE, DEPARTURE_DATE, HOLDER_ID, HOLDER_TYPE, ARRIVAL_TIME, ARRIVING_LATE, ARRIVED_AT, CANCELLED_AT, CREATED_AT, UPDATED_AT, IS_SURVEY_COMPLETED, SHORT_CODE, HOLIDAY_TYPE, ARRIVAL_SLOT, ADDED_TO_MY_HAVEN_APP, DELETED_DATE, IS_DELETED ) 
