FROM "HAVEN_RAW"."DIG_ARRIVALS_ETLEAP"."ARRIVAL";

CREATE OR REPLACE VIEW HAVEN_BASE_ETLEAP.DIG_ARRIVALS.CARAVAN 
( FILE_MODIFICATION_TIME, CODE, NUMBER, STATUS, CREATED_AT, UPDATED_AT, ID, ARRIVAL_HOLDER_ID, DELETED_DATE, IS_DELETED ) 
