CREATE OR REPLACE VIEW HAVEN_BASE_ETLEAP.DIG_ARRIVALS.MIGRATIONS 
( ID, TIMESTAMP, NAME, FILE_MODIFICATION_TIME, DELETED_DATE, IS_DELETED ) 
AS SELECT "ID", "TIMESTAMP", "NAME", "FILE_MODIFICATION_TIME", "END_DATE", DECODE(END_DATE, NULL, FALSE, TRUE) 
FROM "HAVEN_RAW"."DIG_ARRIVALS_ETLEAP"."MIGRATIONS";

CREATE OR REPLACE VIEW HAVEN_BASE_ETLEAP.DIG_ARRIVALS.TRANSPORTATION 
( TYPE, STATUS, LICENSE_PLATE, CREATED_AT, UPDATED_AT, ARRIVAL_ID, ID, FILE_MODIFICATION_TIME, DELETED_DATE, IS_DELETED ) 
