USE ROLE dba;

USE SCHEMA haven_base_etleap.seaware;

ALTER SESSION SET JDBC_QUERY_RESULT_FORMAT='JSON';

SELECT get_ddl('VIEW', 'BLL_INV_AVAILABILITY');

create or replace view BLL_INV_AVAILABILITY
( DATE_,	PARK_CODE,	GRADE_CODE,	PRODUCT_TYPE,	PITCHES,	NA_ABS,	HELD,	RSRV_UA,	RSRV_OL,	RSRV_OB,	ALLOC,	CAP,	AVAIL,	FIRM,	ASGN_ABS,	GTY_ABS,	TIMESTAMP,	BK,	OFR,	RSRV_SP) 
AS SELECT "DATE_", "PARK_CODE", "GRADE_CODE", "PRODUCT_TYPE", "PITCHES", "NA_ABS", "HELD", "RSRV_UA", "RSRV_OL", "RSRV_OB", "ALLOC", "CAP", "AVAIL", "FIRM", "ASGN_ABS", "GTY_ABS", "TIMESTAMP", "BK", "OFR", "RSRV_SP" 
FROM "HAVEN_RAW"."SEAWARE_ETLEAP"."BLL_INV_AVAILABILITY";

SELECT get_ddl('VIEW', 'BLL_INV_CONTRACT');

create or replace view BLL_INV_CONTRACT
( DATE_, PARK_CODE, GRADE_CODE, PRODUCT_TYPE, CONTRACT_TYPE, PITCHES, NA_ABS, HELD, ALLOC, ASGN_ABS, TIMESTAMP ) 
AS SELECT "DATE_", "PARK_CODE", "GRADE_CODE", "PRODUCT_TYPE", "CONTRACT_TYPE", "PITCHES", "NA_ABS", "HELD", "ALLOC", "ASGN_ABS", "TIMESTAMP" 
FROM "HAVEN_RAW"."SEAWARE_ETLEAP"."BLL_INV_CONTRACT";

