use ROLE dba;

use SCHEMA haven_base.payment_service;

CREATE VIEW HAVEN_BASE.PAYMENT_SERVICE.INTENT
( UNIQUE_ID, SOURCE_SYSTEM, SOURCE_SYSTEM_ID, SOURCE_SYSTEM_REF, AMOUNT_DUE, CREATED_AT, CUSTOMER, CUSTOMER_ADDRESS, META, OPTIONS, "ORDER", STATUS, PAYMENT_REFERENCE, UPDATED_AT, LOCATION, AMOUNT_REFUNDED, ANALYTICS_DATA, PARK_CODE, IS_PAY_BY_LINK, METHOD_OF_PAYMENT )
AS SELECT UNIQUE_ID, SOURCE_SYSTEM, SOURCE_SYSTEM_ID, SOURCE_SYSTEM_REF, AMOUNT_DUE, CREATED_AT, CUSTOMER, CUSTOMER_ADDRESS, META, "OPTIONS", "order", STATUS, PAYMENT_REFERENCE, UPDATED_AT, LOCATION, AMOUNT_REFUNDED, ANALYTICS_DATA, PARK_CODE, IS_PAY_BY_LINK, METHOD_OF_PAYMENT
FROM HAVEN_RAW.PAYMENT_SERVICE.INTENT;

CREATE VIEW HAVEN_BASE.PAYMENT_SERVICE.PAYMENT_AUDIT
( ID, PAYMENT_INTENT_ID, TIMESTAMP_UTC, EVENT_TYPE, EVENT_DETAILS, EVENT_MESSAGE, EVENT_CATEGORY, RESULT )
AS SELECT ID, PAYMENT_INTENT_ID, TIMESTAMP_UTC, EVENT_TYPE, EVENT_DETAILS, EVENT_MESSAGE, EVENT_CATEGORY, "RESULT"
FROM HAVEN_RAW.PAYMENT_SERVICE.PAYMENT_AUDIT;

CREATE VIEW HAVEN_BASE.PAYMENT_SERVICE.PAYMENT_AUTH
( ID, PAYMENT_INTENT_ID, RAW_RESPONSE, CREATED_AT, REQUEST_ID, REASON_CODE, DECISION, PROCESSOR_RESPONSE_CODE, PROCESSOR_RESPONSE_MESSAGE, PROCESSOR_TRANSACTION_ID, RECONCILIATION_ID, TOKEN, INVOICE_NUMBER, TOTAL_AMOUNT, PAYMENT_SESSION_ID, SUCCESS, MERCHANT_REFERENCE_CODE, LOCATION, SOURCE_SYSTEM_TYPE, REFUND_AMOUNT, VOID_TRANSACTION_ID, VOIDED, CARD_BRAND, PAYMENT_METHOD, MERCHANT_ID, STORE_ID, TERMINAL_ID )
AS SELECT ID, PAYMENT_INTENT_ID, RAW_RESPONSE, CREATED_AT, REQUEST_ID, REASON_CODE, DECISION, PROCESSOR_RESPONSE_CODE, PROCESSOR_RESPONSE_MESSAGE, PROCESSOR_TRANSACTION_ID, RECONCILIATION_ID, TOKEN, INVOICE_NUMBER, TOTAL_AMOUNT, PAYMENT_SESSION_ID, SUCCESS, MERCHANT_REFERENCE_CODE, LOCATION, SOURCE_SYSTEM_TYPE, REFUND_AMOUNT, VOID_TRANSACTION_ID, VOIDED, CARD_BRAND, PAYMENT_METHOD, MERCHANT_ID, STORE_ID, TERMINAL_ID
FROM HAVEN_RAW.PAYMENT_SERVICE.PAYMENT_AUTH;

CREATE VIEW HAVEN_BASE.PAYMENT_SERVICE.PAYMENT_CAPTURE
( ID, PAYMENT_AUTH_ID, PAYMENT_INTENT_ID, INVOICE_NUMBER, TOTAL_AMOUNT, RAW_RESPONSE, CREATED_AT, REQUEST_ID, REASON_CODE, DECISION, PROCESSOR_RESPONSE_CODE, PROCESSOR_RESPONSE_MESSAGE, PROCESSOR_TRANSACTION_ID, RECONCILIATION_ID, PAYMENT_SESSION_ID, SUCCESS, MERCHANT_REFERENCE_CODE, LOCATION, SOURCE_SYSTEM_TYPE, REFUND_AMOUNT, VOIDED, CARD_BRAND, PAYMENT_METHOD, MERCHANT_ID, STORE_ID, TERMINAL_ID )
SELECT ID, PAYMENT_AUTH_ID, PAYMENT_INTENT_ID, INVOICE_NUMBER, TOTAL_AMOUNT, RAW_RESPONSE, CREATED_AT, REQUEST_ID, REASON_CODE, DECISION, PROCESSOR_RESPONSE_CODE, PROCESSOR_RESPONSE_MESSAGE, PROCESSOR_TRANSACTION_ID, RECONCILIATION_ID, PAYMENT_SESSION_ID, SUCCESS, MERCHANT_REFERENCE_CODE, LOCATION, SOURCE_SYSTEM_TYPE, REFUND_AMOUNT, VOIDED, CARD_BRAND, PAYMENT_METHOD, MERCHANT_ID, STORE_ID, TERMINAL_ID
FROM HAVEN_RAW.PAYMENT_SERVICE.PAYMENT_CAPTURE;

CREATE VIEW HAVEN_BASE.PAYMENT_SERVICE.PAYMENT_REFUND
( ID, PAYMENT_CAPTURE_ID, PAYMENT_INTENT_ID, SUCCESS, VOID, REFUND_AMOUNT, REFUND_MESSAGE, RAW_RESPONSE, CREATED_AT, REQUEST_ID, REASON_CODE, DECISION, PROCESSOR_RESPONSE_CODE, PROCESSOR_RESPONSE_MESSAGE, PROCESSOR_TRANSACTION_ID, RECONCILIATION_ID, MERCHANT_REFERENCE_CODE, MERCHANT_ID, STORE_ID, TERMINAL_ID )
AS SELECT ID, PAYMENT_CAPTURE_ID, PAYMENT_INTENT_ID, SUCCESS, VOID, REFUND_AMOUNT, REFUND_MESSAGE, RAW_RESPONSE, CREATED_AT, REQUEST_ID, REASON_CODE, DECISION, PROCESSOR_RESPONSE_CODE, PROCESSOR_RESPONSE_MESSAGE, PROCESSOR_TRANSACTION_ID, RECONCILIATION_ID, MERCHANT_REFERENCE_CODE, MERCHANT_ID, STORE_ID, TERMINAL_ID
FROM HAVEN_RAW.PAYMENT_SERVICE.PAYMENT_REFUND;

CREATE VIEW HAVEN_BASE.PAYMENT_SERVICE.REFUND
( REQUEST_ID, REFUNDED, REFUND_RESULT, INTENT_ID, STARTED, FINISHED, SOURCE_SYSTEM_UPDATED, ACCOUNTED, FAULTED, COMPENSATED, CRITICAL_FAILURE, CURRENT_STATE, FAULT_STATE, SOURCE_SYSTEM_RESULT, ACCOUNT_RESULT, COMPLETION_RESULT, UPDATED_AT_UTC, DURATION_SECONDS, AMOUNT, CREATED_AT, REQUESTED_BY )
AS SELECT REQUEST_ID, REFUNDED, REFUND_RESULT, INTENT_ID, STARTED, FINISHED, SOURCE_SYSTEM_UPDATED, ACCOUNTED, FAULTED, COMPENSATED, CRITICAL_FAILURE, CURRENT_STATE, FAULT_STATE, SOURCE_SYSTEM_RESULT, ACCOUNT_RESULT, COMPLETION_RESULT, UPDATED_AT_UTC, DURATION_SECONDS, AMOUNT, CREATED_AT, REQUESTED_BY
FROM HAVEN_RAW.PAYMENT_SERVICE.REFUND;

CREATE VIEW HAVEN_BASE.PAYMENT_SERVICE.SESSION
( UNIQUE_ID, INTENT_ID, CREATED_AT, EXPIRES_AT, BILL_PAYER, BILLING_ADDRESS, PROVIDER_DETAILS, CLIENT_IP_ADDRESS, CLIENT_USER_AGENT, RECEIPT_EMAIL_ADDRESS, SHOULD_SEND_PAYMENT_RECEIPT )
AS SELECT UNIQUE_ID, INTENT_ID, CREATED_AT, EXPIRES_AT, BILL_PAYER, BILLING_ADDRESS, PROVIDER_DETAILS, CLIENT_IP_ADDRESS, CLIENT_USER_AGENT, RECEIPT_EMAIL_ADDRESS, SHOULD_SEND_PAYMENT_RECEIPT
FROM HAVEN_RAW.PAYMENT_SERVICE."SESSION";

CREATE VIEW HAVEN_BASE.PAYMENT_SERVICE.TRANSACTION
( UNIQUE_ID, INTENT_ID, TRANSACTION_TYPE, MERCHANT_ID, PAYMENT_METHOD, AMOUNT, TIMESTAMP_UTC, SOURCE_SYSTEM, SOURCE_SYSTEM_TRANSACTION_ID, INVOICE_NUMBER, BANK_TRANSACTION_ID, PROCESSOR_TRANSACTION_ID, MASKED_ACCOUNT_NUMBER, CARD_BRAND, CARD_EXPIRATION_MONTH, CARD_EXPIRATION_YEAR, HAVEN_TRANSACTION_ID, NAME_ON_CARD )
AS SELECT UNIQUE_ID, INTENT_ID, TRANSACTION_TYPE, MERCHANT_ID, PAYMENT_METHOD, AMOUNT, TIMESTAMP_UTC, SOURCE_SYSTEM, SOURCE_SYSTEM_TRANSACTION_ID, INVOICE_NUMBER, BANK_TRANSACTION_ID, PROCESSOR_TRANSACTION_ID, MASKED_ACCOUNT_NUMBER, CARD_BRAND, CARD_EXPIRATION_MONTH, CARD_EXPIRATION_YEAR, HAVEN_TRANSACTION_ID, NAME_ON_CARD
FROM HAVEN_RAW.PAYMENT_SERVICE."TRANSACTION";

CREATE VIEW HAVEN_BASE.PAYMENT_SERVICE.WEB_PAYMENT
( REQUEST_ID, PAYMENT_AUTHORISED, PAYMENT_AUTHORISED_RESULT, PAYMENT_CAPTURED, PAYMENT_CAPTURE_RESULT, INTENT_ID, AMOUNT, STARTED, FINISHED, SOURCE_SYSTEM_UPDATED, ACCOUNTED, FAULTED, COMPENSATED, CRITICAL_FAILURE, CURRENT_STATE, FAULT_STATE, SOURCE_SYSTEM_RESULT, ACCOUNT_RESULT, COMPLETION_RESULT, UPDATED_AT_UTC, DURATION_SECONDS, CREATED_AT, CUSTOMER_SHOULD_RETRY, PAYMENT_AUTHORISED_RESPONSE_CODE, PAYMENT_CAPTURE_RESPONSE_CODE, CLIENT_IP_ADDRESS, CLIENT_USER_AGENT )
